protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // [EF9 breaking change] HasIndex throws on Cosmos — indexing is managed
    // via the container's indexing policy (Azure Portal / Bicep / Terraform).
    // Removed: modelBuilder.Entity<Product>().HasIndex(p => p.Sku);

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // [EF9 breaking change] Discriminator property renamed to "$type".
        // Existing 500K documents use "Discriminator" — preserve the old name
        // so EF9 can read them and direct SQL queries on c.Discriminator still work.
        entity.HasDiscriminator<string>("Discriminator");

        // [EF9 breaking change] id values no longer include the discriminator.
        // Existing documents have id format "Product|123" — preserve that format
        // so point-reads and FindAsync continue to locate existing documents.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

