using Microsoft.EntityFrameworkCore;
class CosmosQuery
{
    // [EF9 breaking change] Cosmos provider no longer supports sync I/O.
    // All queries and saves must use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" name
        // in HasDiscriminator() configuration above.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

